const { spawn } = require('child_process');

exports.handler = async (event) => {
  const record = event.Records[0];
  const s3Event = JSON.parse(record.body);

  const key = s3Event.Records[0].s3.object.key;
  const format = record.eventMetadata.format;

  const convertCommand = ['convert', key, '-format', format, '-quality', '80', 'output.jpg'];

  try {
    await new Promise((resolve, reject) => {
      spawn('magick', convertCommand, { stdio: 'inherit' }).on('exit', (code) => {
        if (code !== 0) {
          reject(new Error(`ImageMagick command failed with code ${code}`));
        } else {
          resolve();
        }
      });
    });
  } catch (error) {
    console.error(error);
    throw error;
  }
};